t.script:

(function () {
  const root = document.getElementById("ls-root");
  const out = document.getElementById("ls-out");
  const statusEl = document.getElementById("ls-status");
  const countEl = document.getElementById("ls-count");
  const metaEl = document.getElementById("ls-meta");
  const jump = document.getElementById("ls-jump");
  const btnPause = document.getElementById("btn-pause");
  const btnAuto = document.getElementById("btn-auto");
  const btnWrap = document.getElementById("btn-wrap");
  const btnClear = document.getElementById("btn-clear");
  const btnDownload = document.getElementById("btn-download");
  const search = document.getElementById("ls-search");
  const matchEl = document.getElementById("ls-match");

  const stageId = root.dataset.stage || window.location.pathname.split("/").pop();
  const MAX_LINES = 5000;          // cap DOM to stay snappy on long sessions
  let autoScroll = true;
  let paused = false;
  let total = 0;
  let filterText = "";             // active filter (lowercased)
  const buffer = [];               // lines received while paused

  function levelClass(text) {
    if (/^[🔌⚠️⏱️❌]/.test(text)) return "lvl-sys";
    if (/\bERROR\b|\bCRITICAL\b|Traceback/.test(text)) return "lvl-error";
    if (/\bWARNING\b/.test(text)) return "lvl-warn";
    if (/\bDEBUG\b/.test(text)) return "lvl-debug";
    return "";
  }

  function escapeHtml(s) {
    return s.replace(/[&<>]/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
  }

  function highlight(raw, term) {
    const lower = raw.toLowerCase();
    let res = "", i = 0, idx;
    while ((idx = lower.indexOf(term, i)) !== -1) {
      res += escapeHtml(raw.slice(i, idx)) +
             "<mark>" + escapeHtml(raw.slice(idx, idx + term.length)) + "</mark>";
      i = idx + term.length;
    }
    return res + escapeHtml(raw.slice(i));
  }

  // Show/hide + highlight one row according to the active filter.
  function decorate(div) {
    const raw = div.__raw;
    if (!filterText) { div.style.display = ""; div.textContent = raw; return; }
    if (raw.toLowerCase().indexOf(filterText) !== -1) {
      div.style.display = ""; div.innerHTML = highlight(raw, filterText);
    } else {
      div.style.display = "none";
    }
  }

  function trim() {
    while (out.childElementCount > MAX_LINES) out.removeChild(out.firstChild);
  }

  function render(text) {
    const div = document.createElement("div");
    div.className = "row " + levelClass(text);
    div.__raw = text;
    decorate(div);
    out.appendChild(div);
    total++;
    trim();
    updateMatch();
    if (autoScroll) out.scrollTop = out.scrollHeight;
  }

  function applyFilter() {
    for (const row of out.children) decorate(row);
    updateMatch();
  }

  function updateMatch() {
    if (!filterText) { matchEl.textContent = ""; return; }
    let n = 0;
    for (const row of out.children) if (row.style.display !== "none") n++;
    matchEl.textContent = n.toLocaleString() + " match";
  }

  function updateCount() {
    countEl.textContent = total.toLocaleString() + " lines" +
      (paused && buffer.length ? "  (+" + buffer.length + " paused)" : "");
  }

  function addLine(text) {
    if (paused) { buffer.push(text); if (buffer.length > MAX_LINES) buffer.shift(); }
    else { render(text); }
    updateCount();
  }

  // --- controls ---
  btnPause.addEventListener("click", function () {
    paused = !paused;
    btnPause.classList.toggle("active", paused);
    btnPause.innerHTML = paused ? "▶ Resume" : "⏸ Pause";
    root.classList.toggle("ls-paused", paused);
    statusEl.textContent = paused ? "Paused" : "Connected";
    if (!paused) { buffer.splice(0).forEach(render); updateCount();
      if (autoScroll) out.scrollTop = out.scrollHeight; }
  });

  btnAuto.addEventListener("click", function () {
    autoScroll = !autoScroll;
    btnAuto.classList.toggle("active", autoScroll);
    if (autoScroll) { jump.style.display = "none"; out.scrollTop = out.scrollHeight; }
  });

  btnWrap.addEventListener("click", function () {
    out.classList.toggle("nowrap");
    btnWrap.classList.toggle("active", out.classList.contains("nowrap"));
  });

  btnClear.addEventListener("click", function () {
    out.innerHTML = ""; total = 0; buffer.length = 0; updateCount(); updateMatch();
  });

  // --- filter ---
  search.addEventListener("input", function () {
    filterText = search.value.trim().toLowerCase();
    applyFilter();
    if (autoScroll) out.scrollTop = out.scrollHeight;
  });
  search.addEventListener("keydown", function (e) {
    if (e.key === "Escape") { search.value = ""; filterText = ""; applyFilter(); }
  });

  // --- download current buffer (all lines, not just the filtered view) ---
  btnDownload.addEventListener("click", function () {
    const lines = Array.from(out.children).map(d => (d.__raw != null ? d.__raw : d.textContent));
    const blob = new Blob([lines.join("\n") + "\n"], { type: "text/plain;charset=utf-8" });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    const name = (root.dataset.name || "logs").replace(/[^A-Za-z0-9._-]/g, "_");
    const ts = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
    a.download = name + "_" + ts + ".log";
    document.body.appendChild(a); a.click(); a.remove();
    setTimeout(function () { URL.revokeObjectURL(a.href); }, 1000);
  });

  // disable auto-scroll if the user scrolls up; show a jump button
  out.addEventListener("scroll", function () {
    const atBottom = out.scrollHeight - out.clientHeight <= out.scrollTop + 24;
    if (!atBottom && autoScroll) {
      autoScroll = false; btnAuto.classList.remove("active"); jump.style.display = "block";
    } else if (atBottom) {
      jump.style.display = "none";
    }
  });
  jump.addEventListener("click", function () {
    autoScroll = true; btnAuto.classList.add("active");
    jump.style.display = "none"; out.scrollTop = out.scrollHeight;
  });

  // --- stream ---
  const es = new EventSource(`/log/stream/${stageId}/feed`);
  let started = null;
  es.onopen = function () {
    root.classList.remove("ls-down");
    if (!paused) statusEl.textContent = "Connected";
    if (!started) { started = new Date(); metaEl.textContent = "Streaming since " + started.toLocaleTimeString(); }
  };
  es.onmessage = function (e) { addLine(e.data); };
  es.onerror = function () {
    root.classList.add("ls-down");
    statusEl.textContent = "Reconnecting…";
  };
  window.addEventListener("beforeunload", function () { es.close(); });
})();
